from flask import Flask, request, jsonify
from web3 import Web3
from eth_account.messages import encode_defunct
import os
import time
import secrets
import threading

app = Flask(__name__)

w3 = Web3()

NONCE_TTL_SECONDS = int(os.getenv("NONCE_TTL_SECONDS", "300"))
AUTH_MESSAGE_PREFIX = os.getenv("AUTH_MESSAGE_PREFIX", "Sign this message to authenticate.")
HOST = os.getenv("HOST", "0.0.0.0")
PORT = int(os.getenv("PORT", "8000"))
DEBUG = os.getenv("DEBUG", "false").lower() == "true"

nonces = {}
lock = threading.Lock()


def now_ts():
    return int(time.time())


def cleanup_nonces():
    current = now_ts()
    expired = []
    with lock:
        for address, entry in nonces.items():
            if entry["expires_at"] <= current:
                expired.append(address)
        for address in expired:
            nonces.pop(address, None)


def normalize_address(address: str):
    if not address or not isinstance(address, str):
        return None
    try:
        return Web3.to_checksum_address(address)
    except Exception:
        return None


def build_auth_message(address: str, nonce: str) -> str:
    return f"{AUTH_MESSAGE_PREFIX}\nAddress: {address}\nNonce: {nonce}"


@app.route("/health", methods=["GET"])
def health():
    return jsonify({"status": "ok"}), 200


@app.route("/auth/nonce", methods=["POST"])
def get_nonce():
    cleanup_nonces()
    data = request.get_json(silent=True) or {}
    address = normalize_address(data.get("address"))
    if not address:
        return jsonify({"error": "Invalid Ethereum address"}), 400

    nonce = secrets.token_hex(16)
    expires_at = now_ts() + NONCE_TTL_SECONDS
    message = build_auth_message(address, nonce)

    with lock:
        nonces[address] = {
            "nonce": nonce,
            "message": message,
            "expires_at": expires_at,
        }

    return jsonify(
        {
            "address": address,
            "nonce": nonce,
            "message": message,
            "expires_at": expires_at,
        }
    ), 200


@app.route("/auth/verify", methods=["POST"])
def verify_signature():
    cleanup_nonces()
    data = request.get_json(silent=True) or {}

    address = normalize_address(data.get("address"))
    signature = data.get("signature")
    message = data.get("message")

    if not address:
        return jsonify({"authenticated": False, "error": "Invalid Ethereum address"}), 400
    if not signature or not isinstance(signature, str):
        return jsonify({"authenticated": False, "error": "Missing or invalid signature"}), 400
    if not message or not isinstance(message, str):
        return jsonify({"authenticated": False, "error": "Missing or invalid message"}), 400

    with lock:
        entry = nonces.get(address)

    if not entry:
        return jsonify({"authenticated": False, "error": "Nonce not found or expired"}), 401

    if entry["expires_at"] <= now_ts():
        with lock:
            nonces.pop(address, None)
        return jsonify({"authenticated": False, "error": "Nonce expired"}), 401

    if message != entry["message"]:
        return jsonify({"authenticated": False, "error": "Message does not match issued challenge"}), 401

    try:
        encoded_message = encode_defunct(text=message)
        recovered_address = w3.eth.account.recover_message(encoded_message, signature=signature)
        recovered_address = Web3.to_checksum_address(recovered_address)
    except Exception as e:
        return jsonify({"authenticated": False, "error": f"Signature verification failed: {str(e)}"}), 401

    if recovered_address != address:
        return jsonify(
            {
                "authenticated": False,
                "error": "Recovered address does not match provided address",
                "recovered_address": recovered_address,
            }
        ), 401

    with lock:
        nonces.pop(address, None)

    return jsonify(
        {
            "authenticated": True,
            "address": address,
            "recovered_address": recovered_address,
        }
    ), 200


if __name__ == "__main__":
    app.run(host=HOST, port=PORT, debug=DEBUG)